UPDATE products SET price = 900, retailPrice = 1300 WHERE name = 'Granddaddy Purple' AND category = 'flower';
-- Girl Scout Cookies: $13/gram = 1300 cents
UPDATE products SET price = 1300, retailPrice = 1800 WHERE name = 'Girl Scout Cookies' AND category = 'flower';
-- Gelato #33: $14/gram = 1400 cents
UPDATE products SET price = 1400, retailPrice = 1900 WHERE name = 'Gelato #33' AND category = 'flower';
-- Wedding Cake: $15/gram = 1500 cents
UPDATE products SET price = 1500, retailPrice = 2000 WHERE name = 'Wedding Cake' AND category = 'flower';
-- Jack Herer: $11/gram = 1100 cents
UPDATE products SET price = 1100, retailPrice = 1500 WHERE name = 'Jack Herer' AND category = 'flower';
-- Zkittlez: $12/gram = 1200 cents
UPDATE products SET price = 1200, retailPrice = 1600 WHERE name = 'Zkittlez' AND category = 'flower';
-- Gorilla Glue #4: $14/gram = 1400 cents
UPDATE products SET price = 1400, retailPrice = 1900 WHERE name = 'Gorilla Glue #4' AND category = 'flower';
-- Summer 2025 Harvest - Purple Haze: $10/gram = 1000 cents
UPDATE products SET price = 1000, retailPrice = 1400 WHERE name LIKE '%Purple Haze%' AND category = 'flower';
SELECT id, name, price, retailPrice, category FROM products WHERE category = 'flower' ORDER BY price DESC LIMIT 15;

